function openDb(){return new Promise((resolve,reject)=>{const req=indexedDB.open(DB_NAME,DB_VERSION);req.onupgradeneeded=()=>{const d=req.result;if(!d.objectStoreNames.contains('profiles'))d.createObjectStore('profiles',{keyPath:'id'});if(!d.objectStoreNames.contains('meta'))d.createObjectStore('meta',{keyPath:'key'});if(!d.objectStoreNames.contains('cache'))d.createObjectStore('cache',{keyPath:'key'});};req.onsuccess=()=>resolve(req.result);req.onerror=()=>reject(req.error);});}
function idb(store,mode='readonly'){return db.transaction(store,mode).objectStore(store)}
function idbGet(store,key){return new Promise((resolve,reject)=>{const r=idb(store).get(key);r.onsuccess=()=>resolve(r.result);r.onerror=()=>reject(r.error)})}
function idbAll(store){return new Promise((resolve,reject)=>{const r=idb(store).getAll();r.onsuccess=()=>resolve(r.result);r.onerror=()=>reject(r.error)})}
function idbPut(store,value){return new Promise((resolve,reject)=>{const r=idb(store,'readwrite').put(value);r.onsuccess=()=>resolve();r.onerror=()=>reject(r.error)})}
function idbDelete(store,key){return new Promise((resolve,reject)=>{const r=idb(store,'readwrite').delete(key);r.onsuccess=()=>resolve();r.onerror=()=>reject(r.error)})}
async function saveProfile(p=profile){p.updatedAt=new Date().toISOString();await idbPut('profiles',deepClone(p));profiles=await idbAll('profiles');updateProfileSelectors();}
async function setActiveProfile(id){await idbPut('meta',{key:'activeProfileId',value:id});}

function normalizeProfile(p){
  const base=standardProfile(); const out={...base,...p};
  out.equipment={...base.equipment,...(p.equipment||{})};
  out.central={...base.central,...(p.central||{})};
  out.central.windProfiles={...deepClone(WIND_PROFILES),...(p.central?.windProfiles||{})};
  out.central.weights={...base.central.weights,...(p.central?.weights||{})};
  out.central.listDisplay={...base.central.listDisplay,...(p.central?.listDisplay||{})};
  out.central.listDisplay.profiles={...deepClone(DISPLAY_PROFILES),...(p.central?.listDisplay?.profiles||{})};
  out.locations=(p.locations?.length?p.locations:base.locations).map(x=>({...x,horizon:Array.isArray(x.horizon)&&x.horizon.length===8?x.horizon:[0,0,0,0,0,0,0,0],obstacles:x.obstacles||[]}));
  out.planning={...base.planning,...(p.planning||{})}; out.ui={...base.ui,...(p.ui||{})};
  return out;
}

async function init(){
  document.documentElement.dataset.environment=ENV;
  document.body.classList.toggle('env-test',ENV==='test');
  document.body.classList.toggle('env-prod',ENV==='prod');
  document.title=BUILD.documentTitle || `Astro Night Planner ${RELEASE}`;
  const headerVersion=document.getElementById('headerVersion');
  if(headerVersion)headerVersion.textContent=RELEASE;
  const headerEnvironment=document.getElementById('headerEnvironmentText');
  if(headerEnvironment){headerEnvironment.hidden=ENV==='prod';headerEnvironment.textContent=ENV==='test'?' · TESTVERSION':'';}
  const badge=document.getElementById('environmentBadge');
  badge.hidden=ENV==='prod';
  if(ENV==='test')badge.textContent=BUILD.badgeText || 'TESTVERSION';
  db=await openDb(); profiles=(await idbAll('profiles')).map(normalizeProfile);
  if(!profiles.length){const p=standardProfile();await idbPut('profiles',p);profiles=[p];}
  const active=await idbGet('meta','activeProfileId'); profile=profiles.find(x=>x.id===active?.value)||profiles.find(x=>x.id==='standard')||profiles[0];
  await setActiveProfile(profile.id); draft=deepClone(profile); currentMainTab=profile.ui?.mainTab||'plan'; currentSettingsTab=profile.ui?.settingsTab||'equipment';
  selectedDateKey=profile.planning.dateKey||dateKeyFor(new Date(),activeLocation().timezone); page=profile.planning.page||1;
  updateProfileSelectors(); bindGlobal(); render(); registerPwa(); loadCatalog(); fetchWeather();
}

function bindGlobal(){
  document.querySelectorAll('[data-main-tab]').forEach(btn=>btn.addEventListener('click',()=>switchMain(btn.dataset.mainTab)));
  document.getElementById('headerProfileSelect').addEventListener('change',async e=>{const found=profiles.find(x=>x.id===e.target.value);if(!found)return;profile=normalizeProfile(found);draft=deepClone(profile);dirtySections.clear();await setActiveProfile(profile.id);selectedDateKey=profile.planning.dateKey||dateKeyFor(new Date(),activeLocation().timezone);page=1;render();fetchWeather();});
  importInput.addEventListener('change',handleImportFile);
  window.addEventListener('beforeinstallprompt',e=>{e.preventDefault();installPrompt=e;document.getElementById('installButton').hidden=false;});
  document.getElementById('installButton').addEventListener('click',async()=>{if(installPrompt){installPrompt.prompt();await installPrompt.userChoice;installPrompt=null;document.getElementById('installButton').hidden=true;}});
  document.getElementById('reloadForUpdate').addEventListener('click',()=>location.reload());
}
function updateProfileSelectors(){
  const select=document.getElementById('headerProfileSelect'); if(!select)return;
  select.innerHTML=profiles.sort((a,b)=>a.name.localeCompare(b.name,'de')).map(p=>`<option value="${esc(p.id)}" ${profile&&p.id===profile.id?'selected':''}>${esc(p.name)}</option>`).join('');
  document.getElementById('headerProfileName').textContent=profile?.name||'Standard';
}
async function switchMain(tab){scrollByTab[currentMainTab]=scrollY;currentMainTab=tab;profile.ui.mainTab=tab;await saveProfile();render();requestAnimationFrame(()=>scrollTo({top:scrollByTab[tab]||0,behavior:'instant'}));}

function activeLocation(){return profile.locations.find(x=>x.id===profile.selectedLocationId)||profile.locations[0]||standardProfile().locations[0]}
function activeScope(){return profile.equipment.telescopes.find(x=>x.id===profile.equipment.selectedTelescopeId)}
function activeCamera(){return profile.equipment.cameras.find(x=>x.id===profile.equipment.selectedCameraId)}
function fov(){const s=activeScope(),c=activeCamera();if(!s||!c||!s.focalLength)return null;return {width:57.2958*c.sensorWidth/s.focalLength,height:57.2958*c.sensorHeight/s.focalLength,pixelScale:206.265*c.pixelSize/s.focalLength}}
function esc(v){return String(v??'').replace(/[&<>"]/g,s=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;'}[s]))}
function fmt(v,d=0){return Number.isFinite(v)?Number(v).toFixed(d):'–'}
function toRad(x){return x*Math.PI/180} function toDeg(x){return x*180/Math.PI}
function dateKeyFor(date,tz='Europe/Berlin'){return new Intl.DateTimeFormat('en-CA',{timeZone:tz,year:'numeric',month:'2-digit',day:'2-digit'}).format(date)}
function addDays(key,n){const d=new Date(`${key}T12:00:00Z`);d.setUTCDate(d.getUTCDate()+n);return d.toISOString().slice(0,10)}
function fmtDate(key,tz){return new Intl.DateTimeFormat('de-DE',{timeZone:tz,weekday:'short',day:'2-digit',month:'2-digit'}).format(new Date(`${key}T12:00:00Z`))}
function fmtTime(date,tz){if(!date||isNaN(date))return'–';return new Intl.DateTimeFormat('de-DE',{timeZone:tz,hour:'2-digit',minute:'2-digit'}).format(date)}
function fmtDateTime(date,tz){return new Intl.DateTimeFormat('de-DE',{timeZone:tz,day:'2-digit',month:'2-digit',hour:'2-digit',minute:'2-digit'}).format(date)}

function julian(date){return date.getTime()/86400000+2440587.5}
function gmst(date){const d=julian(date)-2451545;return ((18.697374558+24.06570982441908*d)%24+24)%24}
function altitude(raHours,decDeg,date,lat,lon){const ha=toRad((((gmst(date)+lon/15-raHours)%24+24)%24)*15);const p=toRad(lat),d=toRad(decDeg);return toDeg(Math.asin(clamp(Math.sin(p)*Math.sin(d)+Math.cos(p)*Math.cos(d)*Math.cos(ha),-1,1)))}
function azimuth(raHours,decDeg,date,lat,lon){const ha=toRad((((gmst(date)+lon/15-raHours)%24+24)%24)*15);const p=toRad(lat),d=toRad(decDeg);const y=Math.sin(ha),x=Math.cos(ha)*Math.sin(p)-Math.tan(d)*Math.cos(p);return (toDeg(Math.atan2(y,x))+180+360)%360}
function sunCoords(date){const n=julian(date)-2451545;const L=(280.46+.9856474*n)%360;const g=toRad((357.528+.9856003*n)%360);const lambda=toRad(L+1.915*Math.sin(g)+.02*Math.sin(2*g));const eps=toRad(23.439-.0000004*n);const ra=Math.atan2(Math.cos(eps)*Math.sin(lambda),Math.cos(lambda));const dec=Math.asin(Math.sin(eps)*Math.sin(lambda));return {raHours:((toDeg(ra)/15)%24+24)%24,decDeg:toDeg(dec)}}
function sunAltitude(date,loc){const c=sunCoords(date);return altitude(c.raHours,c.decDeg,date,loc.latitude,loc.longitude)}
function moonCoords(date){const d=julian(date)-2451543.5;const N=toRad(125.1228-.0529538083*d);const i=toRad(5.1454);const w=toRad(318.0634+.1643573223*d);const a=60.2666;const e=.0549;const M=toRad((115.3654+13.0649929509*d)%360);let E=M+e*Math.sin(M)*(1+e*Math.cos(M));for(let k=0;k<3;k++)E=E-(E-e*Math.sin(E)-M)/(1-e*Math.cos(E));const xv=a*(Math.cos(E)-e),yv=a*Math.sqrt(1-e*e)*Math.sin(E);const v=Math.atan2(yv,xv),r=Math.hypot(xv,yv);const xh=r*(Math.cos(N)*Math.cos(v+w)-Math.sin(N)*Math.sin(v+w)*Math.cos(i));const yh=r*(Math.sin(N)*Math.cos(v+w)+Math.cos(N)*Math.sin(v+w)*Math.cos(i));const zh=r*Math.sin(v+w)*Math.sin(i);const lon=Math.atan2(yh,xh),lat=Math.atan2(zh,Math.hypot(xh,yh));const eps=toRad(23.4393);const xe=Math.cos(lon)*Math.cos(lat),ye=Math.sin(lon)*Math.cos(lat)*Math.cos(eps)-Math.sin(lat)*Math.sin(eps),ze=Math.sin(lon)*Math.cos(lat)*Math.sin(eps)+Math.sin(lat)*Math.cos(eps);const ra=Math.atan2(ye,xe),dec=Math.atan2(ze,Math.hypot(xe,ye));return{raHours:((toDeg(ra)/15)%24+24)%24,decDeg:toDeg(dec)}}
function moonIllumination(date){const syn=29.53058867;const age=((julian(date)-2451550.1)%syn+syn)%syn;return (1-Math.cos(2*Math.PI*age/syn))/2*100}
function findCrossings(start,end,loc,threshold,fn=sunAltitude){const step=5*60000;let prevT=start,prev=fn(start,loc)-threshold;const out=[];for(let t=start.getTime()+step;t<=end.getTime();t+=step){const dt=new Date(t),v=fn(dt,loc)-threshold;if(prev===0||v===0||prev*v<0){const frac=Math.abs(prev)/(Math.abs(prev)+Math.abs(v));out.push({time:new Date(prevT.getTime()+frac*(dt-prevT)),descending:prev>v});}prev=v;prevT=dt;}return out}
function nightData(key,loc){const center=new Date(`${key}T12:00:00Z`),start=new Date(center.getTime()-2*3600000),end=new Date(center.getTime()+26*3600000);const cross=t=>findCrossings(start,end,loc,t);const c0=cross(-.833),c6=cross(-6),c12=cross(-12),c18=cross(-18);const desc=a=>a.find(x=>x.descending)?.time,asc=a=>[...a].reverse().find(x=>!x.descending)?.time;const sunset=desc(c0)||new Date(`${key}T18:00:00Z`),sunrise=asc(c0)||new Date(sunset.getTime()+12*3600000);const moonFn=(date,l)=>{const c=moonCoords(date);return altitude(c.raHours,c.decDeg,date,l.latitude,l.longitude)};const mc=findCrossings(sunset,sunrise,loc,0,moonFn);let moonMax=-90,moonTransit=null;for(let t=sunset.getTime();t<=sunrise.getTime();t+=10*60000){const a=moonFn(new Date(t),loc);if(a>moonMax){moonMax=a;moonTransit=new Date(t)}}return{sunset,sunrise,civilDusk:desc(c6)||sunset,civilDawn:asc(c6)||sunrise,nauticalDusk:desc(c12)||desc(c6)||sunset,nauticalDawn:asc(c12)||asc(c6)||sunrise,astronomicalDusk:desc(c18)||desc(c12)||sunset,astronomicalDawn:asc(c18)||asc(c12)||sunrise,moonrise:mc.find(x=>!x.descending)?.time,moonset:mc.find(x=>x.descending)?.time,moonTransit,moonMaxAltitude:moonMax,moonIllumination:moonIllumination(new Date((sunset.getTime()+sunrise.getTime())/2))}}
function planningWindow(night,key){switch(key){case'sunset':return{start:night.sunset,end:night.sunrise,label:'Sonnenuntergang bis Sonnenaufgang'};case'civil':return{start:night.civilDusk,end:night.civilDawn,label:'Bürgerliche Nacht'};case'astronomicalTwilight':return{start:night.nauticalDusk,end:night.nauticalDawn,label:'Nautische und astronomische Nacht'};case'astronomicalNight':return{start:night.astronomicalDusk,end:night.astronomicalDawn,label:'Astronomische Nacht'};default:return{start:night.nauticalDusk,end:night.nauticalDawn,label:'Nautischer Planungszeitraum'}}}
function angularSeparation(aRa,aDec,bRa,bDec){const a=toRad(aRa*15),b=toRad(bRa*15),da=toRad(aDec),db=toRad(bDec);return toDeg(Math.acos(clamp(Math.sin(da)*Math.sin(db)+Math.cos(da)*Math.cos(db)*Math.cos(a-b),-1,1)))}
function horizonAt(loc,az){const arr=loc.horizon||[0,0,0,0,0,0,0,0];const pos=((az%360)+360)%360/45;const i=Math.floor(pos)%8,j=(i+1)%8,f=pos-Math.floor(pos);return arr[i]*(1-f)+arr[j]*f}
function objectStats(obj,window,loc,minAlt){const points=[];let max=-90,best=window.start,visibleMs=0;const count=49;for(let i=0;i<count;i++){const t=new Date(window.start.getTime()+(window.end-window.start)*i/(count-1));const alt=altitude(obj.raHours,obj.decDeg,t,loc.latitude,loc.longitude);const az=azimuth(obj.raHours,obj.decDeg,t,loc.latitude,loc.longitude);const effectiveMin=Math.max(minAlt,horizonAt(loc,az));points.push({t,alt,az});if(alt>max){max=alt;best=t}if(i&&alt>=effectiveMin)visibleMs+=(window.end-window.start)/(count-1)}const moon=moonCoords(best);const moonAlt=altitude(moon.raHours,moon.decDeg,best,loc.latitude,loc.longitude);return{points,maxAltitude:max,bestTime:best,visibleHours:visibleMs/3600000,meridian:best,moonDistance:angularSeparation(obj.raHours,obj.decDeg,moon.raHours,moon.decDeg),moonAltitude:moonAlt}}

function currentWindProfile(){return profile.planning.temporaryWindProfile||profile.central.activeWindProfile}
function currentDisplayProfile(){return profile.planning.temporaryDisplayProfile||profile.central.listDisplay.activeProfile}
function windUnitLabel(unit=profile.central.windUnit){return unit==='ms'?'m/s':'km/h'}
function windFromKmh(value,unit=profile.central.windUnit){return unit==='ms'?value/3.6:value}
function convertWindValue(value,fromUnit,toUnit){if(fromUnit===toUnit)return value;return toUnit==='ms'?value/3.6:value*3.6}
function windThresholds(){return profile.central.windProfiles[currentWindProfile()]||WIND_PROFILES.normal}
function weatherForWindow(window){if(!weatherModels.length)return null;const rows=[];for(const model of weatherModels){for(let i=0;i<model.time.length;i++){const t=new Date(model.time[i]);if(t>=window.start&&t<=window.end)rows.push({...model.values[i],time:t,model:model.name})}}if(!rows.length)return null;const finite=k=>rows.map(r=>r[k]).filter(Number.isFinite);const avg=k=>{const a=finite(k);return a.length?a.reduce((x,y)=>x+y,0)/a.length:NaN};const max=k=>{const a=finite(k);return a.length?Math.max(...a):NaN};const dewGap=avg('temperature')-avg('dewPoint');const cloud=avg('cloud');const windKmh=avg('wind'),gustKmh=max('gust'),jetKmh=avg('jet'),visibility=avg('visibility');const wind=windFromKmh(windKmh),gust=windFromKmh(gustKmh),jet=windFromKmh(jetKmh);const transparency=clamp((visibility/24000)*100-cloud*.45,0,100);const seeing=clamp(82-windKmh*2.1-(avg('cloudHigh')||0)*.12,0,100);const w=windThresholds();const windScore=wind<w.windGreen?100:wind<w.windYellow?60:20;const dewScore=dewGap>profile.central.dew.green?100:dewGap>=profile.central.dew.yellow?55:15;return{rows,cloud,wind,gust,jet,windKmh,gustKmh,jetKmh,dewGap,visibility,transparency,seeing,windScore,dewScore}}
function scoreObject(obj,stats,weather,window,night){const w=profile.central.weights;const duration=Math.max(.1,(window.end-window.start)/3600000);const altitudeScore=clamp((stats.maxAltitude-15)/60*100,0,100),durationScore=clamp(stats.visibleHours/duration*100,0,100);const moonPenalty=stats.moonAltitude<=0?100:clamp((stats.moonDistance-15)/75*100,0,100)*(1-night.moonIllumination/180);const cloud=weather?100-weather.cloud:55,trans=weather?weather.transparency:55,seeing=weather?weather.seeing:55,wind=weather?weather.windScore:55,dew=weather?weather.dewScore:55;const total=w.clouds*cloud+w.transparency*trans+w.seeing*seeing+w.wind*wind+w.dew*dew+w.moon*moonPenalty+w.altitude*altitudeScore+w.duration*durationScore;return clamp(total/100,0,100)}
function scoreClass(v){return v>=70?'good':v>=45?'warn':'bad'}
function fitsSensor(obj){const f=fov();if(!f||!obj.majorArcMin)return'–';const ratio=Math.max(obj.majorArcMin/60/f.width,obj.minorArcMin/60/f.height);return ratio<=.82?'gut':ratio<=1.05?'knapp':'zu groß'}

async function loadCatalog(){try{const cached=await idbGet('cache','catalog-v10');if(cached?.value?.length){catalog=mergeCatalog(cached.value);render()}let rows=null,lastError=null;for(const url of [LOCAL_CATALOG_URL,REMOTE_CATALOG_URL]){try{const response=await fetch(url,{cache:'no-cache'});if(!response.ok)throw new Error(`${url}: HTTP ${response.status}`);const candidate=await response.json();if(!Array.isArray(candidate)||!candidate.length)throw new Error(`${url}: ungültiger Katalog`);rows=candidate;break}catch(error){lastError=error}}if(!rows)throw lastError||new Error('Kein Katalog verfügbar');const converted=rows.map(r=>({id:r[0],name:r[1],aliases:r[2]||[],type:r[3],raHours:r[4],decDeg:r[5],magnitude:r[6]??null,surfaceBrightness:r[7]??null,majorArcMin:r[8]||0,minorArcMin:r[9]||r[8]||0,constellation:r[10]||'–',recommendedFilters:r[11]||[],catalogs:r[12]||['Zusatzkatalog'],positionAngleDeg:Number.isFinite(r[13])?r[13]:0}));catalog=mergeCatalog(converted);await idbPut('cache',{key:'catalog-v10',value:converted,updatedAt:new Date().toISOString()});render();}catch(err){console.warn('Katalog-Fallback aktiv',err)}}
function mergeCatalog(remote){const map=new Map();for(const o of [...remote,...BUILTIN_OBJECTS]){const key=o.id.replace(/\s/g,'').toUpperCase();map.set(key,{...(map.get(key)||{}),...o,aliases:[...new Set([...(map.get(key)?.aliases||[]),...(o.aliases||[])])],catalogs:[...new Set([...(map.get(key)?.catalogs||[]),...(o.catalogs||[])])]});}return [...map.values()]}

async function fetchWeather(){weatherError='';weatherModels=[];render();const loc=activeLocation();const vars='temperature_2m,dew_point_2m,relative_humidity_2m,cloud_cover,cloud_cover_low,cloud_cover_mid,cloud_cover_high,visibility,precipitation,wind_speed_10m,wind_gusts_10m,wind_speed_250hPa';const specs=[['DWD ICON','icon_seamless'],['ECMWF IFS','ecmwf_ifs025'],['NOAA GFS','gfs_seamless']];const settled=await Promise.allSettled(specs.map(async([name,model])=>{const u=new URL('https://api.open-meteo.com/v1/forecast');u.search=new URLSearchParams({latitude:loc.latitude,longitude:loc.longitude,elevation:loc.elevation||'',hourly:vars,models:model,wind_speed_unit:'kmh',timezone:'auto',forecast_days:'8'});const r=await fetch(u);if(!r.ok)throw new Error(`${name}: HTTP ${r.status}`);const j=await r.json();const h=j.hourly;return{name,time:h.time,values:h.time.map((_,i)=>({temperature:h.temperature_2m?.[i],dewPoint:h.dew_point_2m?.[i],humidity:h.relative_humidity_2m?.[i],cloud:h.cloud_cover?.[i],cloudLow:h.cloud_cover_low?.[i],cloudMid:h.cloud_cover_mid?.[i],cloudHigh:h.cloud_cover_high?.[i],visibility:h.visibility?.[i],precip:h.precipitation?.[i],wind:h.wind_speed_10m?.[i],gust:h.wind_gusts_10m?.[i],jet:h.wind_speed_250hPa?.[i]}))}}));weatherModels=settled.filter(x=>x.status==='fulfilled').map(x=>x.value);const failures=settled.filter(x=>x.status==='rejected');if(!weatherModels.length)weatherError='Keine Wettermodelle konnten geladen werden.';else if(failures.length)weatherError=`${failures.length} Wettermodell(e) derzeit nicht verfügbar.`;render();}

function render(){
  document.querySelectorAll('[data-main-tab]').forEach(b=>b.classList.toggle('active',b.dataset.mainTab===currentMainTab));
  document.getElementById('headerProfileName').textContent=profile.name;
  app.innerHTML=currentMainTab==='plan'?renderPlan():renderSettings();
  bindRendered(); drawMiniCharts();
}
function dateKeys(){const today=dateKeyFor(new Date(),activeLocation().timezone);return Array.from({length:8},(_,i)=>addDays(today,i))}
function renderPlan(){
  const loc=activeLocation(),keys=dateKeys();if(!keys.includes(selectedDateKey))selectedDateKey=keys[0];const night=nightData(selectedDateKey,loc),window=planningWindow(night,profile.planning.planningWindow);const weather=weatherForWindow(window);const objects=computeObjects(window,night,weather);const display=profile.central.listDisplay.profiles[currentDisplayProfile()]||DISPLAY_PROFILES.standard;profile.planning.pageSize=display.pageSize||profile.planning.pageSize||20;const totalPages=Math.max(1,Math.ceil(objects.length/profile.planning.pageSize));page=clamp(page,1,totalPages);const start=(page-1)*profile.planning.pageSize,shown=objects.slice(start,start+profile.planning.pageSize);const selected=catalog.find(o=>o.id===profile.planning.selectedObjectId)||shown[0]?.object||catalog[0];if(selected)profile.planning.selectedObjectId=selected.id;
  return `<div data-page="plan">
    <section class="card"><div class="section-title-row"><div><h2>Planungsnacht</h2><div class="muted">${esc(loc.name)} · ${fmt(loc.latitude,4)}°, ${fmt(loc.longitude,4)}°</div></div><button id="weatherRefresh">Wetter aktualisieren</button></div>
      <div class="date-buttons">${keys.map((k,i)=>`<button data-date="${k}" class="${k===selectedDateKey?'active':''}">${i===0?'Heute':i===1?'Morgen':`+${i}`}<br><span class="small">${fmtDate(k,loc.timezone)}</span></button>`).join('')}</div>
      <div class="grid four" style="margin-top:14px"><div class="metric"><div class="label">Sonnenuntergang</div><div class="value">${fmtTime(night.sunset,loc.timezone)}</div></div><div class="metric"><div class="label">Gewählter Zeitraum</div><div class="value">${fmtTime(window.start,loc.timezone)}–${fmtTime(window.end,loc.timezone)}</div><div class="small muted">${window.label}</div></div><div class="metric"><div class="label">Astronomische Dunkelheit</div><div class="value">${fmtTime(night.astronomicalDusk,loc.timezone)}–${fmtTime(night.astronomicalDawn,loc.timezone)}</div></div><div class="metric"><div class="label">Sonnenaufgang</div><div class="value">${fmtTime(night.sunrise,loc.timezone)}</div></div></div>
      <div class="grid four" style="margin-top:12px"><div class="metric"><div class="label">Mondaufgang</div><div class="value">${fmtTime(night.moonrise,loc.timezone)}</div></div><div class="metric"><div class="label">Mondkulmination</div><div class="value">${fmtTime(night.moonTransit,loc.timezone)} · ${fmt(night.moonMaxAltitude)}°</div></div><div class="metric"><div class="label">Monduntergang</div><div class="value">${fmtTime(night.moonset,loc.timezone)}</div></div><div class="metric"><div class="label">Mondbeleuchtung</div><div class="value">${fmt(night.moonIllumination)} %</div></div></div>
    </section>
    <section class="card"><div class="section-title-row"><h2>Profile für diese Planung</h2><span class="small muted">Temporäre Auswahl überschreibt den Standard nicht.</span></div><div class="toolbar">
      <label>Aufnahmequalitätsprofil<select id="planWindProfile"><option value="">Standard: ${esc(profile.central.windProfiles[profile.central.activeWindProfile].name)}</option>${Object.entries(profile.central.windProfiles).map(([k,v])=>`<option value="${k}" ${profile.planning.temporaryWindProfile===k?'selected':''}>${esc(v.name)}</option>`).join('')}</select></label><button id="makeWindDefault" ${!profile.planning.temporaryWindProfile?'disabled':''}>Als Standard übernehmen</button>
      <label>Darstellungsprofil<select id="planDisplayProfile"><option value="">Standard: ${esc(profile.central.listDisplay.profiles[profile.central.listDisplay.activeProfile].name)}</option>${Object.entries(profile.central.listDisplay.profiles).map(([k,v])=>`<option value="${k}" ${profile.planning.temporaryDisplayProfile===k?'selected':''}>${esc(v.name)}</option>`).join('')}</select></label><button id="makeDisplayDefault" ${!profile.planning.temporaryDisplayProfile?'disabled':''}>Als Standard übernehmen</button>
    </div></section>
    ${renderWeather(window,weather,loc)}
    <section class="card"><div class="section-title-row"><h2>Objektauswahl</h2><span class="muted">${objects.length} Treffer aus ${catalog.length} Katalogobjekten</span></div>${renderFilters()}
      ${pagination(totalPages,objects.length)}${renderObjectTable(shown,display.columns,loc,window,night)}${pagination(totalPages,objects.length)}
    </section>
    ${selected?renderFraming(selected,window,loc):''}
    ${renderMeteoblue(loc)}
  </div>`;
}
function computeObjects(window,night,weather){const p=profile.planning,needle=p.search.trim().toLocaleLowerCase('de');return catalog.filter(o=>!p.catalogs?.length||o.catalogs.some(c=>p.catalogs.includes(c))).filter(o=>!p.types?.length||p.types.includes(o.type)).filter(o=>o.magnitude==null||o.magnitude<=p.maxMagnitude).filter(o=>!o.majorArcMin||(o.majorArcMin>=p.minSize&&o.majorArcMin<=p.maxSize)).filter(o=>!needle||[o.id,o.name,o.constellation,...(o.aliases||[])].join(' ').toLocaleLowerCase('de').includes(needle)).map(object=>{const stats=objectStats(object,window,activeLocation(),p.minAltitude);return{object,stats,score:scoreObject(object,stats,weather,window,night),fit:fitsSensor(object)}}).filter(x=>x.stats.maxAltitude>=p.minAltitude&&x.stats.visibleHours>=p.minVisibleHours&&(x.stats.moonDistance>=p.minMoonDistance||x.stats.moonAltitude<=0)&&(!p.onlyFits||['gut','knapp'].includes(x.fit))).sort((a,b)=>b.score-a.score)}
function renderFilters(){const cats=['Messier','NGC','IC','Sh2','Abell','Zusatzkatalog'];const types=[...new Set(catalog.map(o=>o.type))].sort((a,b)=>a.localeCompare(b,'de'));return `<details ${profile.central.collapsed.filters?'':'open'} id="filterDetails"><summary>Filter und Planungszeitraum</summary><div class="filters" style="margin-top:13px"><label>Planungszeitraum<select id="planningWindow"><option value="sunset">Sonnenuntergang–Sonnenaufgang</option><option value="civil">Bürgerliche Nacht</option><option value="nautical">Nautischer Planungszeitraum</option><option value="astronomicalTwilight">Nautisch + astronomisch</option><option value="astronomicalNight">Astronomische Nacht</option></select></label><label>Suche<input id="objectSearch" value="${esc(profile.planning.search)}" placeholder="M31, NGC, Rosette …"></label><label>Max. Magnitude<input id="maxMagnitude" type="number" step="0.1" value="${profile.planning.maxMagnitude}"></label><label>Mindesthöhe<input id="minAltitude" type="number" min="0" max="90" value="${profile.planning.minAltitude}"></label><label>Mind. Sichtbarkeit (h)<input id="minVisibleHours" type="number" step="0.25" min="0" value="${profile.planning.minVisibleHours}"></label><label>Mind. Mondabstand<input id="minMoonDistance" type="number" min="0" max="180" value="${profile.planning.minMoonDistance}"></label><label>Min. Größe (′)<input id="minSize" type="number" min="0" value="${profile.planning.minSize}"></label><label>Max. Größe (′)<input id="maxSize" type="number" min="0" value="${profile.planning.maxSize}"></label></div><div class="divider"></div><div class="small muted">Kataloge</div><div class="chip-list">${cats.map(c=>`<label class="chip"><input type="checkbox" data-catalog="${c}" ${profile.planning.catalogs.includes(c)?'checked':''}>${c==='Sh2'?'Sharpless 2':c==='Abell'?'Abell-PN':c}</label>`).join('')}</div><div class="small muted" style="margin-top:12px">Objekttypen (keine Auswahl = alle)</div><div class="chip-list">${types.map(t=>`<label class="chip"><input type="checkbox" data-object-type="${esc(t)}" ${profile.planning.types.includes(t)?'checked':''}>${esc(t)}</label>`).join('')}</div><label class="chip" style="margin-top:12px"><input id="onlyFits" type="checkbox" ${profile.planning.onlyFits?'checked':''}>Nur Objekte, die auf den Sensor passen</label></details>`}
function pagination(totalPages,total){const pageSize=profile.planning.pageSize;const buttons=[];const from=Math.max(1,page-2),to=Math.min(totalPages,page+2);for(let i=from;i<=to;i++)buttons.push(`<button data-page-number="${i}" class="${i===page?'active':''}">${i}</button>`);return `<div class="pagination"><div class="result-summary"><span>${total} Treffer</span><label>Objekte/Seite <select id="pageSizeSelect"><option>10</option><option>20</option><option>50</option><option>100</option></select></label></div><div class="pages"><button data-page-number="1" ${page===1?'disabled':''}>«</button><button data-page-number="${page-1}" ${page===1?'disabled':''}>‹</button>${buttons.join('')}<button data-page-number="${page+1}" ${page===totalPages?'disabled':''}>›</button><button data-page-number="${totalPages}" ${page===totalPages?'disabled':''}>»</button></div></div>`}
function renderObjectTable(items,columns,loc,window,night){const heads={score:'Bewertung',name:'Objekt',maxAltitude:'Max. Höhe',visibleHours:'Sichtbar',meridian:'Meridian',framing:'Framing',miniChart:'Höhenprofil',bestTime:'Beste Zeit',moonDistance:'Mondabstand',weather:'Wetter',size:'Größe',magnitude:'Mag.',filters:'Filter'};return `<div class="object-table-wrap"><table class="object-table"><thead><tr>${columns.map(c=>`<th>${heads[c]||c}</th>`).join('')}</tr></thead><tbody>${items.map(x=>`<tr>${columns.map(c=>objectCell(c,x,loc,window,night)).join('')}</tr>`).join('')||`<tr><td colspan="${columns.length}">Keine Objekte entsprechen den Filtern.</td></tr>`}</tbody></table></div>`}
function objectCell(c,x,loc,window,night){const o=x.object,s=x.stats;switch(c){case'score':return`<td><span class="score-badge ${scoreClass(x.score)}">${fmt(x.score)}</span></td>`;case'name':return`<td><div class="object-name">${esc(o.id)} · ${esc(o.name)}</div><div class="small muted">${esc(o.type)} · ${esc(o.constellation)} · ${esc(o.catalogs.join(', '))}</div></td>`;case'maxAltitude':return`<td>${fmt(s.maxAltitude)}°</td>`;case'visibleHours':return`<td>${fmt(s.visibleHours,1)} h</td>`;case'meridian':return`<td>${fmtTime(s.meridian,loc.timezone)}<br><span class="small muted">${fmt(s.maxAltitude)}°</span></td>`;case'framing':return`<td><button data-frame-object="${esc(o.id)}">${x.fit}</button></td>`;case'miniChart':return`<td><canvas class="mini-chart" width="230" height="92" data-points="${encodeURIComponent(JSON.stringify(s.points.map(p=>[p.t.getTime(),p.alt])))}" data-start="${window.start.getTime()}" data-end="${window.end.getTime()}" data-astro-start="${night.astronomicalDusk.getTime()}" data-astro-end="${night.astronomicalDawn.getTime()}" data-naut-start="${night.nauticalDusk.getTime()}" data-naut-end="${night.nauticalDawn.getTime()}" data-min-alt="${profile.planning.minAltitude}"></canvas></td>`;case'bestTime':return`<td>${fmtTime(s.bestTime,loc.timezone)}</td>`;case'moonDistance':return`<td>${fmt(s.moonDistance)}°</td>`;case'weather':return`<td>${weatherModels.length?'Modellkonsens':'–'}</td>`;case'size':return`<td>${fmt(o.majorArcMin)}′ × ${fmt(o.minorArcMin)}′</td>`;case'magnitude':return`<td>${o.magnitude??'–'}</td>`;case'filters':return`<td>${esc((o.recommendedFilters||[]).join(', ')||'–')}</td>`;default:return'<td>–</td>'}}
function renderWeather(window,w,loc){const notice=weatherError?`<div class="notice warn">${esc(weatherError)}</div>`:'';if(!weatherModels.length)return`<section class="card"><h2>Wetter und Aufnahmequalität</h2>${notice}<div class="loading-card"><div class="spinner"></div><p>Wettermodelle werden geladen …</p></div></section>`;const summary=w||weatherForWindow(window);if(!summary)return`<section class="card"><h2>Wetter und Aufnahmequalität</h2>${notice}<div class="notice warn">Für diesen Planungszeitraum liegen noch keine stündlichen Modellwerte vor.</div></section>`;const unit=windUnitLabel(),rows=summary.rows.filter((r,i,a)=>i%Math.max(1,Math.floor(a.length/30))===0).slice(0,36);const jetClass=summary.jet<profile.central.jet.green?'good':summary.jet<=profile.central.jet.yellow?'warn':'bad';return`<section class="card"><div class="section-title-row"><h2>Wetter und Aufnahmequalität</h2><span class="muted">${weatherModels.map(x=>x.name).join(' · ')}</span></div>${notice}<div class="grid four"><div class="metric"><div class="label">Wolken gesamt</div><div class="value ${scoreClass(100-summary.cloud)}">${fmt(summary.cloud)} %</div></div><div class="metric"><div class="label">Transparenz-Tendenz</div><div class="value ${scoreClass(summary.transparency)}">${fmt(summary.transparency)}/100</div></div><div class="metric"><div class="label">Seeing-Tendenz</div><div class="value ${scoreClass(summary.seeing)}">${fmt(summary.seeing)}/100</div></div><div class="metric"><div class="label">Tauabstand</div><div class="value ${summary.dewGap>profile.central.dew.green?'good':summary.dewGap>=profile.central.dew.yellow?'warn':'bad'}">${fmt(summary.dewGap,1)} °C</div></div><div class="metric"><div class="label">Wind</div><div class="value">${fmt(summary.wind,1)} ${unit}</div></div><div class="metric"><div class="label">Böen maximal</div><div class="value">${fmt(summary.gust,1)} ${unit}</div></div><div class="metric"><div class="label">Jetstream</div><div class="value ${jetClass}">${fmt(summary.jet,1)} ${unit}</div></div><div class="metric"><div class="label">Sichtweite</div><div class="value">${fmt(summary.visibility/1000,1)} km</div></div><div class="metric"><div class="label">Planungszeitraum</div><div class="value">${fmtTime(window.start,loc.timezone)}–${fmtTime(window.end,loc.timezone)}</div></div></div><details ${profile.central.collapsed.weather?'':'open'} id="weatherDetails"><summary>Stündliche Modellwerte</summary><div class="weather-scroll" style="margin-top:12px"><table class="weather-table"><thead><tr><th>Zeit</th><th>Modell</th><th>Wolken</th><th>tief</th><th>mittel</th><th>hoch</th><th>Wind (${unit})</th><th>Böen (${unit})</th><th>Tauabstand</th><th>Jetstream (${unit})</th></tr></thead><tbody>${rows.map(r=>{const jet=windFromKmh(r.jet),jc=jet<profile.central.jet.green?'good':jet<=profile.central.jet.yellow?'warn':'bad';return`<tr><td>${fmtDateTime(r.time,loc.timezone)}</td><td>${esc(r.model)}</td><td>${fmt(r.cloud)}%</td><td>${fmt(r.cloudLow)}%</td><td>${fmt(r.cloudMid)}%</td><td>${fmt(r.cloudHigh)}%</td><td>${fmt(windFromKmh(r.wind),1)}</td><td>${fmt(windFromKmh(r.gust),1)}</td><td>${fmt(r.temperature-r.dewPoint,1)}°</td><td class="${jc}">${fmt(jet,1)}</td></tr>`}).join('')}</tbody></table></div></details></section>`}
function renderFraming(o,window,loc){const f=fov(),stats=objectStats(o,window,loc,profile.planning.minAltitude);const frameW=f?clamp(90*f.width/Math.max(f.width,f.height,4),12,75):40,frameH=f?clamp(90*f.height/Math.max(f.width,f.height,4),12,75):30;const objW=clamp(90*(o.majorArcMin/60)/Math.max(f?.width||4,f?.height||4,4),3,85),objH=clamp(objW*(o.minorArcMin||o.majorArcMin)/(o.majorArcMin||1),3,85);const target=encodeURIComponent(`${o.raHours*15} ${o.decDeg}`);return`<section class="card" id="framingCard"><div class="section-title-row"><div><h2>Rahmung: ${esc(o.id)} · ${esc(o.name)}</h2><div class="muted">${esc(o.type)} · ${fmt(o.majorArcMin)}′ × ${fmt(o.minorArcMin)}′</div></div><select id="framingObjectSelect" style="width:auto;max-width:350px">${catalog.slice().sort((a,b)=>a.id.localeCompare(b.id,'de',{numeric:true})).map(x=>`<option value="${esc(x.id)}" ${x.id===o.id?'selected':''}>${esc(x.id)} · ${esc(x.name)}</option>`).join('')}</select></div><div class="framing-view"><iframe title="Aladin Lite" src="https://aladin.cds.unistra.fr/AladinLite/?target=${target}&fov=${Math.max(f?.width||2,f?.height||2)*1.6}&survey=P%2FDSS2%2Fcolor"></iframe><div class="frame-overlay" style="display:${profile.central.frameVisible?'block':'none'};width:${frameW}%;height:${frameH}%;transform:translate(-50%,-50%) rotate(${profile.planning.frameRotation}deg)"></div><div class="object-overlay" style="display:${profile.central.objectSizeVisible?'block':'none'};width:${objW}%;height:${objH}%;transform:translate(-50%,-50%) rotate(${profile.planning.objectRotation+(o.positionAngleDeg||0)}deg)"></div><div class="framing-info"><div>Höhe: ${fmt(stats.maxAltitude)}°<br>${fmtTime(stats.bestTime,loc.timezone)}</div><div>${f?`${fmt(f.width,2)}° × ${fmt(f.height,2)}°<br>${fmt(f.pixelScale,2)}″/px`:'Kein Setup gewählt'}</div></div></div><div class="framing-controls"><label class="chip"><input id="frameVisible" type="checkbox" ${profile.central.frameVisible?'checked':''}>Setup-Rahmen anzeigen</label><label>Kamerarotation <input id="frameRotation" type="range" min="0" max="180" value="${profile.planning.frameRotation}"></label><label class="chip"><input id="objectSizeVisible" type="checkbox" ${profile.central.objectSizeVisible?'checked':''}>Objektgröße anzeigen</label><label>Objektrotation <input id="objectRotation" class="short-range" type="range" min="0" max="180" value="${profile.planning.objectRotation}"></label><label>Zeit im Planungsfenster <input id="framingTime" type="range" min="0" max="100" value="${profile.planning.timeFraction*100}"></label></div></section>`}
function renderMeteoblue(loc){const q=encodeURIComponent(`${loc.name} ${loc.latitude},${loc.longitude}`);return`<section class="card"><details ${profile.central.meteoblueCollapsed?'':'open'} id="meteoblueDetails"><summary><strong>Meteoblue Astronomy Seeing</strong> · unabhängige Kontrollvorhersage</summary><div class="notice" style="margin-top:12px">Meteoblue wird bewusst nicht in die automatische Modellbewertung eingerechnet.</div><iframe title="Meteoblue Astronomy Seeing" src="https://www.meteoblue.com/de/wetter/outdoorsports/seeing/${q}" style="width:100%;height:720px;border:0;border-radius:12px;margin-top:12px;background:white"></iframe></details></section>`}

function renderSettings(){return`<div data-page="settings"><section class="card"><div class="section-title-row"><div><h2>Einstellungen</h2><div class="muted">Lokales Profil „${esc(profile.name)}“ · Speicherung in IndexedDB</div></div>${renderProfileBar()}</div><div class="settings-tabs" style="margin-top:16px">${[['equipment','Ausrüstung'],['central','Zentrale Einstellungen'],['locations','Standorte & Horizont'],['info','Info']].map(([k,n])=>`<button data-settings-tab="${k}" class="${currentSettingsTab===k?'active':''} ${dirtySections.has(k)?'dirty-dot':''}">${n}</button>`).join('')}</div></section><section class="settings-section ${currentSettingsTab==='equipment'?'active':''}">${renderEquipment()}</section><section class="settings-section ${currentSettingsTab==='central'?'active':''}">${renderCentral()}</section><section class="settings-section ${currentSettingsTab==='locations'?'active':''}">${renderLocations()}</section><section class="settings-section ${currentSettingsTab==='info'?'active':''}">${renderInfo()}</section></div>`}
function renderProfileBar(){return`<div class="profile-bar"><select id="settingsProfileSelect">${profiles.map(p=>`<option value="${esc(p.id)}" ${p.id===profile.id?'selected':''}>${esc(p.name)}</option>`).join('')}</select><button id="newProfile">Neu</button><button id="duplicateProfile">Duplizieren</button><button id="renameProfile">Umbenennen</button><button id="deleteProfile" class="danger" ${profiles.length===1?'disabled':''}>Löschen</button></div>`}
function renderEquipment(){return`<div class="card"><div class="section-title-row"><h2>Teleskope</h2><button id="addTelescope">Teleskop hinzufügen</button></div><div class="equipment-list">${draft.equipment.telescopes.map(s=>`<div class="equipment-row" data-scope-row="${s.id}"><label>Name<input data-scope="name" value="${esc(s.name)}"></label><label>Brennweite mm<input data-scope="focalLength" type="number" value="${s.focalLength}"></label><label>Öffnung mm<input data-scope="aperture" type="number" value="${s.aperture||''}"></label><label class="chip"><input data-selected-scope type="radio" name="selectedScope" value="${s.id}" ${draft.equipment.selectedTelescopeId===s.id?'checked':''}>Aktiv</label><button data-delete-scope="${s.id}" class="danger">Entfernen</button></div>`).join('')}</div><div class="divider"></div><div class="section-title-row"><h2>Kameras</h2><button id="addCamera">Kamera hinzufügen</button></div><div class="equipment-list">${draft.equipment.cameras.map(c=>`<div class="equipment-row" data-camera-row="${c.id}"><label>Name<input data-camera="name" value="${esc(c.name)}"></label><label>Sensorbreite mm<input data-camera="sensorWidth" type="number" step="0.01" value="${c.sensorWidth}"></label><label>Sensorhöhe mm<input data-camera="sensorHeight" type="number" step="0.01" value="${c.sensorHeight}"></label><label>Pixel µm<input data-camera="pixelSize" type="number" step="0.01" value="${c.pixelSize}"></label><label class="chip"><input data-selected-camera type="radio" name="selectedCamera" value="${c.id}" ${draft.equipment.selectedCameraId===c.id?'checked':''}>Aktiv</label><button data-delete-camera="${c.id}" class="danger">Entfernen</button></div>`).join('')}</div><div class="divider"></div><div class="section-title-row"><span class="save-state">${dirtySections.has('equipment')?'Ungespeicherte Änderungen':'Gespeichert'}</span><button data-save-section="equipment" class="primary">Ausrüstung speichern</button></div></div>`}
function renderCentral(){const c=draft.central;const total=Object.values(c.weights).reduce((a,b)=>a+Number(b||0),0);return`<div class="card"><div class="section-title-row"><h2>Wind und Aufnahmequalität</h2><span class="save-state">${dirtySections.has('centralWind')?'Ungespeicherte Änderungen':'Gespeichert'}</span></div><div class="grid two"><label>Einheit für Wind, Böen und Jetstream<select id="windUnit"><option value="kmh" ${c.windUnit==='kmh'?'selected':''}>km/h</option><option value="ms" ${c.windUnit==='ms'?'selected':''}>m/s</option></select></label><label>Aktiv<select id="activeWindProfile">${Object.entries(c.windProfiles).map(([k,v])=>`<option value="${k}" ${c.activeWindProfile===k?'selected':''}>${esc(v.name)}</option>`).join('')}</select></label></div><div class="grid three" style="margin-top:12px">${Object.entries(c.windProfiles).map(([k,v])=>`<div class="metric"><strong>${esc(v.name)}</strong><label>Wind grün unter (${windUnitLabel(c.windUnit)})<input data-wind-profile="${k}" data-field="windGreen" type="number" value="${v.windGreen}"></label><label>Wind gelb bis (${windUnitLabel(c.windUnit)})<input data-wind-profile="${k}" data-field="windYellow" type="number" value="${v.windYellow}"></label><label>Böen grün unter (${windUnitLabel(c.windUnit)})<input data-wind-profile="${k}" data-field="gustGreen" type="number" value="${v.gustGreen}"></label><label>Böen gelb bis (${windUnitLabel(c.windUnit)})<input data-wind-profile="${k}" data-field="gustYellow" type="number" value="${v.gustYellow}"></label></div>`).join('')}</div><div class="grid two" style="margin-top:12px"><div class="metric"><strong>Tauabstand</strong><label>Grün über °C<input id="dewGreen" type="number" value="${c.dew.green}"></label><label>Gelb ab °C<input id="dewYellow" type="number" value="${c.dew.yellow}"></label></div><div class="metric"><strong>Jetstream</strong><label>Grün unter (${windUnitLabel(c.windUnit)})<input id="jetGreen" type="number" value="${c.jet.green}"></label><label>Gelb bis (${windUnitLabel(c.windUnit)})<input id="jetYellow" type="number" value="${c.jet.yellow}"></label></div></div><div class="section-title-row" style="margin-top:14px"><span></span><button data-save-section="centralWind" class="primary">Rubrik speichern</button></div></div>
  <div class="card"><div class="section-title-row"><h2>Deep-Sky-Gewichtung</h2><span class="weight-total ${total===100?'ok':'error'}">Summe: ${total} %</span></div><div class="notice">Nur ganzzahlige Eingabefelder. Speichern ist nur bei exakt 100 % möglich.</div><div class="weight-grid" style="margin-top:12px">${Object.entries({clouds:'Wolken',transparency:'Transparenz',seeing:'Seeing',wind:'Wind/Böen',dew:'Tauabstand',moon:'Mond',altitude:'Objekthöhe',duration:'Sichtbarkeitsdauer'}).map(([k,n])=>`<label>${n} %<input data-weight="${k}" type="number" min="0" max="100" step="1" value="${c.weights[k]}"></label>`).join('')}</div><div class="section-title-row" style="margin-top:14px"><span class="save-state">${dirtySections.has('weights')?'Ungespeicherte Änderungen':'Gespeichert'}</span><button data-save-section="weights" class="primary" ${total!==100?'disabled':''}>Gewichtung speichern</button></div></div>
  <div class="card"><div class="section-title-row"><h2>Anzeige und Planung</h2><span class="save-state">${dirtySections.has('display')?'Ungespeicherte Änderungen':'Gespeichert'}</span></div><div class="grid two"><label>Standard-Planungszeitraum<select id="defaultPlanningWindow">${[['sunset','Sonnenuntergang–Sonnenaufgang'],['civil','Bürgerliche Nacht'],['nautical','Nautischer Planungszeitraum'],['astronomicalTwilight','Nautisch + astronomisch'],['astronomicalNight','Astronomische Nacht']].map(([k,n])=>`<option value="${k}" ${c.defaultPlanningWindow===k?'selected':''}>${n}</option>`).join('')}</select></label><label>Darstellungsprofil – Aktiv<select id="activeDisplayProfile">${Object.entries(c.listDisplay.profiles).map(([k,v])=>`<option value="${k}" ${c.listDisplay.activeProfile===k?'selected':''}>${esc(v.name)}</option>`).join('')}</select></label></div><div class="grid three" style="margin-top:12px">${Object.entries(c.listDisplay.profiles).map(([k,v])=>`<div class="metric"><strong>${esc(v.name)}</strong><label>Objekte/Seite<select data-display-page-size="${k}">${[10,20,50,100].map(n=>`<option ${v.pageSize===n?'selected':''}>${n}</option>`).join('')}</select></label><div class="small muted" style="margin:8px 0">Sichtbare Spalten</div>${DISPLAY_COLUMNS.map(([id,n])=>`<label class="chip"><input type="checkbox" data-display-column-profile="${k}" data-column="${id}" ${v.columns.includes(id)?'checked':''}>${n}</label>`).join('')}</div>`).join('')}</div><div class="grid two" style="margin-top:12px"><label class="chip"><input id="defaultFrameVisible" type="checkbox" ${c.frameVisible?'checked':''}>Setup-Rahmen standardmäßig anzeigen</label><label class="chip"><input id="defaultObjectVisible" type="checkbox" ${c.objectSizeVisible?'checked':''}>Objektgröße standardmäßig anzeigen</label><label class="chip"><input id="defaultMeteoblueCollapsed" type="checkbox" ${c.meteoblueCollapsed?'checked':''}>Meteoblue standardmäßig eingeklappt</label></div><div class="section-title-row" style="margin-top:14px"><button id="resetDisplayProfiles">Auf Standard zurücksetzen</button><button data-save-section="display" class="primary">Rubrik speichern</button></div></div>`}
function renderLocations(){const loc=draft.locations.find(x=>x.id===draft.selectedLocationId)||draft.locations[0];const dirs=['N','NO','O','SO','S','SW','W','NW'];return`<div class="card"><div class="section-title-row"><h2>Gespeicherte Aufnahmeorte</h2><button id="addLocation">Standort hinzufügen</button></div><div class="toolbar"><label>Standort<select id="locationSelect">${draft.locations.map(x=>`<option value="${x.id}" ${x.id===loc.id?'selected':''}>${esc(x.name)}</option>`).join('')}</select></label><label>Standardstandort<select id="defaultLocationSelect">${draft.locations.map(x=>`<option value="${x.id}" ${x.id===draft.central.defaultLocationId?'selected':''}>${esc(x.name)}</option>`).join('')}</select></label><label>GPS-Verhalten<select id="gpsBehavior"><option value="last" ${draft.central.gpsBehavior==='last'?'selected':''}>Letzten Standort verwenden</option><option value="default" ${draft.central.gpsBehavior==='default'?'selected':''}>Immer Standardstandort</option><option value="ask" ${draft.central.gpsBehavior==='ask'?'selected':''}>Bei jedem Start fragen</option></select></label></div><div class="grid two" style="margin-top:12px"><label>Name<input id="locName" value="${esc(loc.name)}"></label><label>Zeitzone<input id="locTimezone" value="${esc(loc.timezone)}"></label><label>Breitengrad<input id="locLat" type="number" step="0.0001" value="${loc.latitude}"></label><label>Längengrad<input id="locLon" type="number" step="0.0001" value="${loc.longitude}"></label><label>Höhe m<input id="locElevation" type="number" value="${loc.elevation||0}"></label><div class="inline" style="align-self:end"><button id="useGps">GPS verwenden</button><button id="searchLocation">Ort suchen</button><button id="deleteLocation" class="danger" ${draft.locations.length===1?'disabled':''}>Standort löschen</button></div></div></div>
  <div class="card"><div class="section-title-row"><h2>Persönlicher Horizont</h2><span class="save-state">${dirtySections.has('locations')?'Ungespeicherte Änderungen':'Gespeichert'}</span></div><div class="horizon-grid">${dirs.map((d,i)=>`<label><span class="direction-label">${i*45}° = ${d}</span>Horizonthöhe<input data-horizon="${i}" type="number" min="0" max="90" value="${loc.horizon[i]||0}"></label>`).join('')}</div><div class="divider"></div><div class="section-title-row"><h3>Hindernisse</h3><button id="addObstacle">Hindernis hinzufügen</button></div><div class="obstacle-list">${loc.obstacles.map(o=>`<div class="obstacle-row" data-obstacle="${o.id}"><label>Bezeichnung<input data-obstacle-field="name" value="${esc(o.name)}"></label><label>Azimut °<input data-obstacle-field="azimuth" type="number" value="${o.azimuth}"></label><label>Höhe °<input data-obstacle-field="altitude" type="number" value="${o.altitude}"></label><button data-delete-obstacle="${o.id}" class="danger">Entfernen</button></div>`).join('')||'<div class="muted">Keine zusätzlichen Hindernisse erfasst.</div>'}</div><div class="section-title-row" style="margin-top:14px"><span></span><button data-save-section="locations" class="primary">Standort und Horizont speichern</button></div></div>`}
function renderInfo(){return`<div class="card"><h2>Astro Night Planner 1.0</h2><p>Stabile, installierbare PWA für Nachtplanung, astronomisches Wetter, Mond und Dämmerung, Deep-Sky-Auswahl, persönliche Ausrüstung, Standorte, Horizont und Rahmung.</p><div class="storage-status"><div class="metric"><div class="label">Umgebung</div><div class="value">${ENV==='prod'?'Produktion':'Test'}</div></div><div class="metric"><div class="label">Datenbank</div><div class="value small">${DB_NAME}</div></div><div class="metric"><div class="label">Version</div><div class="value">${APP_VERSION}</div></div></div></div>
  <div class="card"><h2>Profile, Sicherung und Wiederherstellung</h2><div class="data-actions"><button id="exportProfile">Aktuelles Profil exportieren</button><button id="exportAll">Komplette Sicherung exportieren</button><button id="importProfile">Profil/Sicherung importieren</button><button id="requestPersistence">Persistenten Speicher anfordern</button></div><div id="storageMessage" class="notice" style="margin-top:12px">Die Daten liegen lokal im Browser. Test- und Produktivversion verwenden getrennte Datenbanken und Caches.</div></div>
  <div class="card help-article"><h2>Browserbasierte Hilfe</h2><div class="help-toc"><a href="#help-plan">Planung</a><a href="#help-weather">Wetter</a><a href="#help-objects">Objektliste</a><a href="#help-framing">Rahmung</a><a href="#help-profiles">Profile & Sicherung</a><a href="docs/ASTRO_NIGHT_PLANNER_HANDBUCH.html" target="_blank">Handbuch öffnen</a></div><section id="help-plan"><h3>Planung</h3><p>Wähle Standort, Datum und Planungszeitraum. Standard ist der nautische Planungszeitraum. Aufnahmequalitäts- und Darstellungsprofil können für die aktuelle Planung temporär geändert werden.</p></section><section id="help-weather"><h3>Wetter</h3><p>ICON, ECMWF IFS und GFS werden über Open-Meteo verglichen. Meteoblue bleibt eine unabhängige Kontrollansicht. Farben bewerten die erwartete Aufnahmequalität, nicht die strukturelle Sicherheit der Ausrüstung.</p></section><section id="help-objects"><h3>Objektliste</h3><p>Die vollständig gefilterte und sortierte Trefferliste wird paginiert. Standard sind 20 Objekte je Seite. Das Mini-Höhenprofil verwendet denselben gewählten Planungszeitraum wie die Berechnung.</p></section><section id="help-framing"><h3>Rahmung</h3><p>Der Setup-Rahmen und die grafische Objektgröße können unabhängig ein- oder ausgeblendet und getrennt rotiert werden. Die Objektgrößenanzeige ist im Standardprofil deaktiviert.</p></section><section id="help-profiles"><h3>Profile und Datensicherung</h3><p>Jedes lokale Benutzerprofil enthält Ausrüstung, Standorte, Horizont, Filter, Profile und Anzeigeoptionen. Exportiere regelmäßig eine vollständige Sicherung.</p></section></div>`}

function bindRendered(){
  document.querySelectorAll('[data-date]').forEach(b=>b.onclick=async()=>{selectedDateKey=b.dataset.date;profile.planning.dateKey=selectedDateKey;page=1;await saveProfile();render();});
  document.getElementById('weatherRefresh')?.addEventListener('click',fetchWeather);
  document.getElementById('planningWindow') && (document.getElementById('planningWindow').value=profile.planning.planningWindow);
  const immediate=[['planningWindow','planningWindow','value'],['objectSearch','search','value'],['maxMagnitude','maxMagnitude','number'],['minAltitude','minAltitude','number'],['minVisibleHours','minVisibleHours','number'],['minMoonDistance','minMoonDistance','number'],['minSize','minSize','number'],['maxSize','maxSize','number'],['onlyFits','onlyFits','checked']];
  for(const [id,key,type] of immediate){const el=document.getElementById(id);if(el)el.addEventListener(type==='value'&&id==='objectSearch'?'input':'change',async()=>{profile.planning[key]=type==='number'?Number(el.value):type==='checked'?el.checked:el.value;page=1;await saveProfile();render();});}
  document.querySelectorAll('[data-catalog]').forEach(el=>el.onchange=async()=>{profile.planning.catalogs=el.checked?[...new Set([...profile.planning.catalogs,el.dataset.catalog])]:profile.planning.catalogs.filter(x=>x!==el.dataset.catalog);page=1;await saveProfile();render();});
  document.querySelectorAll('[data-object-type]').forEach(el=>el.onchange=async()=>{profile.planning.types=el.checked?[...new Set([...profile.planning.types,el.dataset.objectType])]:profile.planning.types.filter(x=>x!==el.dataset.objectType);page=1;await saveProfile();render();});
  document.querySelectorAll('[data-page-number]').forEach(b=>b.onclick=()=>{page=clamp(Number(b.dataset.pageNumber),1,999);profile.planning.page=page;render();document.querySelector('.object-table-wrap')?.scrollIntoView({behavior:'smooth',block:'start'});});
  document.querySelectorAll('#pageSizeSelect').forEach(s=>{s.value=String(profile.planning.pageSize);s.onchange=async()=>{const key=currentDisplayProfile();profile.central.listDisplay.profiles[key].pageSize=Number(s.value);profile.planning.pageSize=Number(s.value);page=1;await saveProfile();render();}});
  document.querySelectorAll('[data-frame-object]').forEach(b=>b.onclick=async()=>{profile.planning.selectedObjectId=b.dataset.frameObject;await saveProfile();render();setTimeout(()=>document.getElementById('framingCard')?.scrollIntoView({behavior:'smooth'}),20);});
  bindPlanProfiles(); bindFraming(); bindDetails(); bindSettings();
}
function bindPlanProfiles(){const w=document.getElementById('planWindProfile'),d=document.getElementById('planDisplayProfile');if(w)w.onchange=async()=>{profile.planning.temporaryWindProfile=w.value||null;await saveProfile();render()};if(d)d.onchange=async()=>{profile.planning.temporaryDisplayProfile=d.value||null;page=1;await saveProfile();render()};document.getElementById('makeWindDefault')?.addEventListener('click',async()=>{if(profile.planning.temporaryWindProfile){profile.central.activeWindProfile=profile.planning.temporaryWindProfile;profile.planning.temporaryWindProfile=null;await saveProfile();draft=deepClone(profile);render()}});document.getElementById('makeDisplayDefault')?.addEventListener('click',async()=>{if(profile.planning.temporaryDisplayProfile){profile.central.listDisplay.activeProfile=profile.planning.temporaryDisplayProfile;profile.planning.temporaryDisplayProfile=null;await saveProfile();draft=deepClone(profile);render()}})}
function bindFraming(){const s=document.getElementById('framingObjectSelect');if(s)s.onchange=async()=>{profile.planning.selectedObjectId=s.value;await saveProfile();render()};for(const [id,key,type] of [['frameVisible','frameVisible','checked'],['objectSizeVisible','objectSizeVisible','checked']]){const e=document.getElementById(id);if(e)e.onchange=async()=>{profile.central[key]=e.checked;await saveProfile();draft=deepClone(profile);render()}}for(const [id,key,scale] of [['frameRotation','frameRotation',1],['objectRotation','objectRotation',1],['framingTime','timeFraction',.01]]){const e=document.getElementById(id);if(e)e.oninput=async()=>{profile.planning[key]=Number(e.value)*scale;await saveProfile();render()}}}
function bindDetails(){const f=document.getElementById('filterDetails');if(f)f.ontoggle=async()=>{profile.central.collapsed.filters=!f.open;await saveProfile()};const w=document.getElementById('weatherDetails');if(w)w.ontoggle=async()=>{profile.central.collapsed.weather=!w.open;await saveProfile()};const m=document.getElementById('meteoblueDetails');if(m)m.ontoggle=async()=>{profile.central.meteoblueCollapsed=!m.open;await saveProfile();draft=deepClone(profile)}}
function bindSettings(){
  document.querySelectorAll('[data-settings-tab]').forEach(b=>b.onclick=async()=>{currentSettingsTab=b.dataset.settingsTab;profile.ui.settingsTab=currentSettingsTab;await saveProfile();render()});
  const ps=document.getElementById('settingsProfileSelect');if(ps)ps.onchange=()=>{document.getElementById('headerProfileSelect').value=ps.value;document.getElementById('headerProfileSelect').dispatchEvent(new Event('change'))};
  document.getElementById('newProfile')?.addEventListener('click',createProfile);document.getElementById('duplicateProfile')?.addEventListener('click',duplicateProfile);document.getElementById('renameProfile')?.addEventListener('click',renameProfile);document.getElementById('deleteProfile')?.addEventListener('click',deleteProfile);
  bindEquipmentDraft();bindCentralDraft();bindLocationDraft();bindInfoActions();
  document.querySelectorAll('[data-save-section]').forEach(b=>b.onclick=()=>saveDraftSection(b.dataset.saveSection));
}
function markDirty(section){dirtySections.add(section);render()}
function bindEquipmentDraft(){document.querySelectorAll('[data-scope-row]').forEach(row=>row.querySelectorAll('[data-scope]').forEach(e=>e.onchange=()=>{const s=draft.equipment.telescopes.find(x=>x.id===row.dataset.scopeRow);s[e.dataset.scope]=e.type==='number'?Number(e.value):e.value;dirtySections.add('equipment')}));document.querySelectorAll('[data-camera-row]').forEach(row=>row.querySelectorAll('[data-camera]').forEach(e=>e.onchange=()=>{const c=draft.equipment.cameras.find(x=>x.id===row.dataset.cameraRow);c[e.dataset.camera]=e.type==='number'?Number(e.value):e.value;dirtySections.add('equipment')}));document.querySelectorAll('[data-selected-scope]').forEach(e=>e.onchange=()=>{draft.equipment.selectedTelescopeId=e.value;dirtySections.add('equipment')});document.querySelectorAll('[data-selected-camera]').forEach(e=>e.onchange=()=>{draft.equipment.selectedCameraId=e.value;dirtySections.add('equipment')});document.getElementById('addTelescope')?.addEventListener('click',()=>{const id=uid('scope');draft.equipment.telescopes.push({id,name:'Neues Teleskop',focalLength:500,aperture:80});draft.equipment.selectedTelescopeId=id;dirtySections.add('equipment');render()});document.getElementById('addCamera')?.addEventListener('click',()=>{const id=uid('cam');draft.equipment.cameras.push({id,name:'Neue Kamera',sensorWidth:23.5,sensorHeight:15.7,pixelSize:3.76});draft.equipment.selectedCameraId=id;dirtySections.add('equipment');render()});document.querySelectorAll('[data-delete-scope]').forEach(b=>b.onclick=()=>{draft.equipment.telescopes=draft.equipment.telescopes.filter(x=>x.id!==b.dataset.deleteScope);draft.equipment.selectedTelescopeId=draft.equipment.telescopes[0]?.id||'';dirtySections.add('equipment');render()});document.querySelectorAll('[data-delete-camera]').forEach(b=>b.onclick=()=>{draft.equipment.cameras=draft.equipment.cameras.filter(x=>x.id!==b.dataset.deleteCamera);draft.equipment.selectedCameraId=draft.equipment.cameras[0]?.id||'';dirtySections.add('equipment');render()})}
function bindCentralDraft(){const set=(id,fn,section)=>{const e=document.getElementById(id);if(e)e.onchange=()=>{fn(e);dirtySections.add(section)}};const unit=document.getElementById('windUnit');if(unit)unit.onchange=()=>{const from=draft.central.windUnit,to=unit.value;if(from!==to){for(const v of Object.values(draft.central.windProfiles)){for(const k of ['windGreen','windYellow','gustGreen','gustYellow'])v[k]=Math.round(convertWindValue(Number(v[k]),from,to)*10)/10}draft.central.jet.green=Math.round(convertWindValue(Number(draft.central.jet.green),from,to)*10)/10;draft.central.jet.yellow=Math.round(convertWindValue(Number(draft.central.jet.yellow),from,to)*10)/10;draft.central.windUnit=to;dirtySections.add('centralWind');render()}};set('activeWindProfile',e=>draft.central.activeWindProfile=e.value,'centralWind');set('dewGreen',e=>draft.central.dew.green=Number(e.value),'centralWind');set('dewYellow',e=>draft.central.dew.yellow=Number(e.value),'centralWind');set('jetGreen',e=>draft.central.jet.green=Number(e.value),'centralWind');set('jetYellow',e=>draft.central.jet.yellow=Number(e.value),'centralWind');document.querySelectorAll('[data-wind-profile]').forEach(e=>e.onchange=()=>{draft.central.windProfiles[e.dataset.windProfile][e.dataset.field]=Number(e.value);dirtySections.add('centralWind')});document.querySelectorAll('[data-weight]').forEach(e=>e.onchange=()=>{draft.central.weights[e.dataset.weight]=Math.round(Number(e.value));dirtySections.add('weights');render()});set('defaultPlanningWindow',e=>draft.central.defaultPlanningWindow=e.value,'display');set('activeDisplayProfile',e=>draft.central.listDisplay.activeProfile=e.value,'display');set('defaultFrameVisible',e=>draft.central.frameVisible=e.checked,'display');set('defaultObjectVisible',e=>draft.central.objectSizeVisible=e.checked,'display');set('defaultMeteoblueCollapsed',e=>draft.central.meteoblueCollapsed=e.checked,'display');document.querySelectorAll('[data-display-page-size]').forEach(e=>e.onchange=()=>{draft.central.listDisplay.profiles[e.dataset.displayPageSize].pageSize=Number(e.value);dirtySections.add('display')});document.querySelectorAll('[data-display-column-profile]').forEach(e=>e.onchange=()=>{const arr=draft.central.listDisplay.profiles[e.dataset.displayColumnProfile].columns;draft.central.listDisplay.profiles[e.dataset.displayColumnProfile].columns=e.checked?[...new Set([...arr,e.dataset.column])]:arr.filter(x=>x!==e.dataset.column);dirtySections.add('display')});document.getElementById('resetDisplayProfiles')?.addEventListener('click',()=>{draft.central.listDisplay.profiles=deepClone(DISPLAY_PROFILES);draft.central.listDisplay.activeProfile='standard';dirtySections.add('display');render()})}
function bindLocationDraft(){const loc=()=>draft.locations.find(x=>x.id===draft.selectedLocationId)||draft.locations[0];const set=(id,field,num=false)=>{const e=document.getElementById(id);if(e)e.onchange=()=>{loc()[field]=num?Number(e.value):e.value;dirtySections.add('locations')}};const ls=document.getElementById('locationSelect');if(ls)ls.onchange=()=>{draft.selectedLocationId=ls.value;render()};set('locName','name');set('locTimezone','timezone');set('locLat','latitude',true);set('locLon','longitude',true);set('locElevation','elevation',true);const dl=document.getElementById('defaultLocationSelect');if(dl)dl.onchange=()=>{draft.central.defaultLocationId=dl.value;dirtySections.add('locations')};const gps=document.getElementById('gpsBehavior');if(gps)gps.onchange=()=>{draft.central.gpsBehavior=gps.value;dirtySections.add('locations')};document.querySelectorAll('[data-horizon]').forEach(e=>e.onchange=()=>{loc().horizon[Number(e.dataset.horizon)]=Number(e.value);dirtySections.add('locations')});document.getElementById('addLocation')?.addEventListener('click',()=>{const id=uid('loc');draft.locations.push({id,name:'Neuer Standort',latitude:48.5,longitude:9,elevation:0,timezone:'Europe/Berlin',horizon:[0,0,0,0,0,0,0,0],obstacles:[]});draft.selectedLocationId=id;dirtySections.add('locations');render()});document.getElementById('deleteLocation')?.addEventListener('click',()=>{draft.locations=draft.locations.filter(x=>x.id!==loc().id);draft.selectedLocationId=draft.locations[0].id;dirtySections.add('locations');render()});document.getElementById('useGps')?.addEventListener('click',()=>navigator.geolocation?.getCurrentPosition(pos=>{loc().latitude=pos.coords.latitude;loc().longitude=pos.coords.longitude;loc().elevation=pos.coords.altitude||loc().elevation;dirtySections.add('locations');render()},err=>alert(`GPS nicht verfügbar: ${err.message}`)));document.getElementById('searchLocation')?.addEventListener('click',async()=>{const name=prompt('Ort oder Postleitzahl:');if(!name)return;try{const r=await fetch(`https://geocoding-api.open-meteo.com/v1/search?name=${encodeURIComponent(name)}&count=5&language=de&format=json`);const j=await r.json();const x=j.results?.[0];if(!x)throw new Error('Kein Treffer');Object.assign(loc(),{name:`${x.name}${x.admin1?`, ${x.admin1}`:''}`,latitude:x.latitude,longitude:x.longitude,elevation:x.elevation||0,timezone:x.timezone||'Europe/Berlin'});dirtySections.add('locations');render()}catch(e){alert(e.message)}});document.getElementById('addObstacle')?.addEventListener('click',()=>{loc().obstacles.push({id:uid('obs'),name:'Baum/Gebäude',azimuth:180,altitude:20});dirtySections.add('locations');render()});document.querySelectorAll('[data-obstacle]').forEach(row=>row.querySelectorAll('[data-obstacle-field]').forEach(e=>e.onchange=()=>{const o=loc().obstacles.find(x=>x.id===row.dataset.obstacle);o[e.dataset.obstacleField]=e.type==='number'?Number(e.value):e.value;dirtySections.add('locations')}));document.querySelectorAll('[data-delete-obstacle]').forEach(b=>b.onclick=()=>{loc().obstacles=loc().obstacles.filter(x=>x.id!==b.dataset.deleteObstacle);dirtySections.add('locations');render()})}
async function saveDraftSection(section){if(section==='equipment'){profile.equipment=deepClone(draft.equipment);dirtySections.delete('equipment')}if(section==='centralWind'){profile.central.windUnit=draft.central.windUnit;profile.central.activeWindProfile=draft.central.activeWindProfile;profile.central.windProfiles=deepClone(draft.central.windProfiles);profile.central.dew=deepClone(draft.central.dew);profile.central.jet=deepClone(draft.central.jet);dirtySections.delete('centralWind')}if(section==='weights'){const total=Object.values(draft.central.weights).reduce((a,b)=>a+Number(b),0);if(total!==100){alert('Die Gewichtung muss exakt 100 % ergeben.');return}profile.central.weights=deepClone(draft.central.weights);dirtySections.delete('weights')}if(section==='display'){profile.central.defaultPlanningWindow=draft.central.defaultPlanningWindow;profile.central.listDisplay=deepClone(draft.central.listDisplay);profile.central.frameVisible=draft.central.frameVisible;profile.central.objectSizeVisible=draft.central.objectSizeVisible;profile.central.meteoblueCollapsed=draft.central.meteoblueCollapsed;dirtySections.delete('display')}if(section==='locations'){profile.locations=deepClone(draft.locations);profile.selectedLocationId=draft.selectedLocationId;profile.central.defaultLocationId=draft.central.defaultLocationId;profile.central.gpsBehavior=draft.central.gpsBehavior;dirtySections.delete('locations')}await saveProfile();draft=deepClone(profile);render();if(section==='locations')fetchWeather()}

async function createProfile(){const name=prompt('Name des neuen Profils:','Neues Profil');if(!name)return;const p=standardProfile();p.id=uid('profile');p.name=name.trim();await idbPut('profiles',p);profiles=await idbAll('profiles');profile=p;draft=deepClone(p);await setActiveProfile(p.id);updateProfileSelectors();render()}
async function duplicateProfile(){const name=prompt('Name der Kopie:',`${profile.name} – Kopie`);if(!name)return;const p=deepClone(profile);p.id=uid('profile');p.name=name.trim();p.createdAt=new Date().toISOString();await idbPut('profiles',p);profiles=await idbAll('profiles');profile=p;draft=deepClone(p);await setActiveProfile(p.id);updateProfileSelectors();render()}
async function renameProfile(){const name=prompt('Neuer Profilname:',profile.name);if(!name)return;profile.name=name.trim();draft.name=profile.name;await saveProfile();render()}
async function deleteProfile(){if(profiles.length===1||!confirm(`Profil „${profile.name}“ wirklich löschen?`))return;await idbDelete('profiles',profile.id);profiles=await idbAll('profiles');profile=normalizeProfile(profiles[0]);draft=deepClone(profile);await setActiveProfile(profile.id);updateProfileSelectors();render()}
function bindInfoActions(){document.getElementById('exportProfile')?.addEventListener('click',()=>downloadJson(`astro-night-planner-profil-${safeName(profile.name)}.json`,{kind:'astro-night-planner-profile',appVersion:APP_VERSION,exportedAt:new Date().toISOString(),profile}));document.getElementById('exportAll')?.addEventListener('click',async()=>downloadJson(`astro-night-planner-sicherung-${new Date().toISOString().slice(0,10)}.json`,{kind:'astro-night-planner-backup',appVersion:APP_VERSION,environment:ENV,exportedAt:new Date().toISOString(),profiles:await idbAll('profiles'),activeProfileId:profile.id}));document.getElementById('importProfile')?.addEventListener('click',()=>importInput.click());document.getElementById('requestPersistence')?.addEventListener('click',async()=>{const el=document.getElementById('storageMessage');if(!navigator.storage?.persist){el.textContent='Dieser Browser unterstützt die Anforderung persistenten Speichers nicht.';return}const granted=await navigator.storage.persist();profile.central.persistentStorageRequested=granted;await saveProfile();el.textContent=granted?'Persistenter Speicher wurde gewährt.':'Der Browser hat persistenten Speicher nicht gewährt; regelmäßige Exporte bleiben wichtig.'})}
function downloadJson(name,data){const blob=new Blob([JSON.stringify(data,null,2)],{type:'application/json'}),a=document.createElement('a');a.href=URL.createObjectURL(blob);a.download=name;a.click();setTimeout(()=>URL.revokeObjectURL(a.href),1000)}
function safeName(s){return s.toLowerCase().replace(/[^a-z0-9äöüß]+/gi,'-').replace(/^-|-$/g,'')}
async function handleImportFile(){const file=importInput.files?.[0];if(!file)return;try{const data=JSON.parse(await file.text());if(data.kind==='astro-night-planner-backup'&&Array.isArray(data.profiles)){if(!confirm(`${data.profiles.length} Profile aus der Sicherung wiederherstellen? Gleichnamige IDs werden überschrieben.`))return;for(const p of data.profiles)await idbPut('profiles',normalizeProfile(p));profiles=await idbAll('profiles');profile=normalizeProfile(profiles.find(x=>x.id===data.activeProfileId)||profiles[0]);await setActiveProfile(profile.id)}else{const raw=data.profile||data;if(!raw.name)throw new Error('Kein gültiges Profil');const p=normalizeProfile(raw);if(profiles.some(x=>x.id===p.id))p.id=uid('profile');await idbPut('profiles',p);profiles=await idbAll('profiles');profile=p;await setActiveProfile(p.id)}draft=deepClone(profile);dirtySections.clear();updateProfileSelectors();render();alert('Import erfolgreich.')}catch(e){alert(`Import fehlgeschlagen: ${e.message}`)}finally{importInput.value=''}}

function drawMiniCharts(){document.querySelectorAll('.mini-chart').forEach(canvas=>{const ctx=canvas.getContext('2d'),w=canvas.width,h=canvas.height;const points=JSON.parse(decodeURIComponent(canvas.dataset.points));const start=Number(canvas.dataset.start),end=Number(canvas.dataset.end),astroS=Number(canvas.dataset.astroStart),astroE=Number(canvas.dataset.astroEnd),nautS=Number(canvas.dataset.nautStart),nautE=Number(canvas.dataset.nautEnd),minAlt=Number(canvas.dataset.minAlt);ctx.clearRect(0,0,w,h);const x=t=>(t-start)/(end-start)*w,y=a=>h-8-clamp(a,0,90)/90*(h-16);ctx.fillStyle='#263343';ctx.fillRect(0,0,w,h);const band=(s,e,fill)=>{ctx.fillStyle=fill;ctx.fillRect(clamp(x(s),0,w),0,clamp(x(e),0,w)-clamp(x(s),0,w),h)};band(nautS,nautE,'#1b2735');band(astroS,astroE,'#101924');for(const t of [nautS,astroS,astroE,nautE]){ctx.beginPath();ctx.strokeStyle='#73849a';ctx.setLineDash([3,3]);ctx.moveTo(x(t),0);ctx.lineTo(x(t),h);ctx.stroke()}ctx.setLineDash([5,4]);ctx.strokeStyle='#d7ad47';ctx.beginPath();ctx.moveTo(0,y(minAlt));ctx.lineTo(w,y(minAlt));ctx.stroke();ctx.setLineDash([]);ctx.strokeStyle='#7ec1ff';ctx.lineWidth=2;ctx.beginPath();points.forEach(([t,a],i)=>i?ctx.lineTo(x(t),y(a)):ctx.moveTo(x(t),y(a)));ctx.stroke();const max=points.reduce((m,p)=>p[1]>m[1]?p:m,points[0]);ctx.fillStyle='#f0c75e';ctx.beginPath();ctx.arc(x(max[0]),y(max[1]),3,0,Math.PI*2);ctx.fill();ctx.fillStyle='#aabbd0';ctx.font='10px sans-serif';ctx.fillText('0°',2,h-2);ctx.fillText('90°',2,10)})}

async function registerPwa(){if(!('serviceWorker'in navigator))return;try{swRegistration=await navigator.serviceWorker.register('sw.js');swRegistration.addEventListener('updatefound',()=>{const worker=swRegistration.installing;worker?.addEventListener('statechange',()=>{if(worker.state==='installed'&&navigator.serviceWorker.controller)document.getElementById('updateBanner').hidden=false})});navigator.serviceWorker.addEventListener('controllerchange',()=>document.getElementById('updateBanner').hidden=false)}catch(e){console.warn('Service Worker konnte nicht registriert werden',e)}}

init().catch(err=>{console.error(err);app.innerHTML=`<section class="card"><h2>Start fehlgeschlagen</h2><div class="notice bad">${esc(err.message||err)}</div><p>Bitte Browserdaten für diese Seite prüfen oder die App neu laden.</p></section>`});
